  "get_precinct_summary": {
    "description": "Retrieves the current records, total confirmed votes, and verification status for a specific precinct.",
    "parameters": {
      "type": "object",
      "properties": {
        "precinct_id": {
          "type": "string",
          "description": "The ID of the precinct (e.g., 'P_05')."
        }
      },
      "required": [
        "precinct_id"
      ]
    },
    "example_output": {
      "precinct_id": "P_05",
      "machine_count": 1200,
      "physical_count": 1245,
      "verification_status": "Pending Audit",
      "total_confirmed_votes": 1200
    }
  },
  "get_discrepancy_details": {
    "description": "Retrieves details about identified discrepancies for a specific batch, including the nature of the mismatch.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The ID of the batch to investigate (e.g., '88-B')."
        }
      },
      "required": [
        "batch_id"
      ]
    },
    "example_output": {
      "batch_id": "88-B",
      "issue": "Write-in mismatch",
      "delta": 45,
      "status": "Unresolved"
    }
  },
  "get_authorized_roster": {
    "description": "Fetches the list of authorized individuals for a specific district to validate write-in votes.",
    "parameters": {
      "type": "object",
      "properties": {
        "district_id": {
          "type": "string",
          "description": "The ID of the district (e.g., 'District 9')."
        }
