        "district_id"
      ]
    },
    "example_output": {
      "authorized_names": [
        "Jane Doe",
        "John Smith"
      ],
      "district": "District 9"
    }
  },
  "get_batch_vote_data": {
    "description": "Retrieves the raw text or data for the physical votes within a specific batch.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The ID of the batch."
        }
      },
      "required": [
        "batch_id"
      ]
    },
    "example_output": {
      "votes": [
        {
          "id": 1,
          "raw_text": "J. Doe"
        },
        {
          "id": 2,
          "raw_text": "Mickey Mouse"
        }
      ]
    }
  },
  "submit_normalization": {
    "description": "Submits the normalized vote mapping for a batch. Maps raw write-in entries to authorized individuals or the 'Scatter' category based on SOP ADJ-04.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The ID of the batch being resolved."
        },
        "mappings": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "vote_id": {
                "type": "integer"
              },
              "normalized_name": {
                "type": "string",
                "description": "The authorized name or 'Scatter'."
              }
            }
          }
        }
      },
      "required": [
        "batch_id",
        "mappings"
      ]
    },
    "example_output": {
      "success": true,
      "reconciled_count": 45,
      "audit_id": "LOG-992"
    }
  },
  "finalize_precinct_certification": {
    "description": "Updates the precinct status to 'Certified' and updates total confirmed votes once all deltas are eliminated.",
    "parameters": {
      "type": "object",
      "properties": {
        "precinct_id": {
          "type": "string",
          "description": "The ID of the precinct."
        },
        "reconciliation_confirmed": {
          "type": "boolean",
          "description": "Must be true to proceed with certification."
        }
      },
      "required": [
        "precinct_id",
        "reconciliation_confirmed"
      ]
    },
    "example_output": {
      "precinct_id": "P_05",
      "new_status": "Certified",
      "final_vote_count": 1245
    }
  }
